use std::collections::HashMap;

struct FeatureStore {
    data_map: HashMap<String, Vec<f64>>
}

impl FeatureStore {
    fn new() -> Self {
        FeatureStore { data_map: HashMap::new() }
    }

    fn add_vector(&mut self, key: impl AsRef<str>, vector: Vec<f64>) {
        let key_str = key.as_ref().to_string();
        self.data_map.insert(key_str, vector);
    }

    fn compute_metrics(&self) -> (HashMap<String, f64>, HashMap<String, f64>) {
        let mut sum_results: HashMap<String, f64> = HashMap::new();
        let mut product_results: HashMap<String, f64> = HashMap::new();

        for (key, vectors) in &self.data_map { 
            if vectors.is_empty() { continue; }

            let sum_val: f64 = vectors.iter().sum();
            let product_val: f64 = vectors.iter().product();

            sum_results.insert(key.clone(), sum_val);
            product_results.insert(key.clone(), product_val);
        }

        (sum_results, product_results)
    }
}

fn main() {
    let mut store = FeatureStore::new();
    store.add_vector("user_id", vec![1.0, 2.0, 3.0]);
    store.add_vector("item_id", vec![4.0, 5.0, 6.0]);
    store.add_vector("context_vec", vec![-1.0, 0.0, 1.0]);

    let (sums, products) = store.compute_metrics();

    println!("Sum Results: {:#?}", sums);
    println!("Product Results: {:#?}", products);
}

use std::collections::VecDeque;

struct MessageData {
    sender_id: u64,
    content_hashes: Vec<u32>,
}

fn process_message_metrics(messages: &Vec<MessageData>) -> (u64, u64) {
    let total_sum: u64 = messages.iter().map(|msg| msg.sender_id).sum();
    let product_of_hashes: u64 = if messages.is_empty() {
        1
    } else {
        messages.iter()
            .fold(1, |acc, msg| acc.checked_mul(msg.content_hashes.iter().product::<u32>() as u64).unwrap_or(0))
    };
    (total_sum, product_of_hashes)
}

fn main() {
    let message1 = MessageData { sender_id: 100, content_hashes: vec![5, 2] };
    let message2 = MessageData { sender_id: 200, content_hashes: vec![3, 4] };
    let message3 = MessageData { sender_id: 300, content_hashes: vec![1, 1] };

    let messages_list = vec![message1, message2, message3];

    let (total_sum, total_product) = process_message_metrics(&messages_list);

    println!("Total Sender ID Sum: {}", total_sum);
    println!("Product of all Content Hashes: {}", total_product);
}

