use std::collections::VecDeque;

struct Point {
    x: f64,
    y: f64,
}

fn process_coordinates(points: Vec<Point>) -> Option<(f64, f64)> {
    if points.is_empty() {
        return None;
    }

    let sum_x: f64 = points.iter().map(|p| p.x).sum();
    let sum_y: f64 = points.iter().map(|p| p.y).sum();

    let max_x = points.iter().fold(f64::NEG_INFINITY, |acc, p| acc.max(p.x));
    let max_y = points.iter().fold(f64::NEG_INFINITY, |acc, p| acc.max(p.y));

    let product = max_x * max_y;

    Some((sum_x + sum_y, product))
}

use std::collections::VecDeque;

struct BytecodeVM {
    stack: VecDeque<i32>,
}

impl BytecodeVM {
    fn new() -> Self {
        BytecodeVM { stack: VecDeque::new() }
    }

    fn push(&mut self, value: i32) {
        self.stack.push_back(value);
    }

    fn pop(&mut self) -> Option<i32> {
        self.stack.pop_back()
    }

    fn calculate_sum(&mut self) -> i32 {
        let mut total = 0;
        while let Some(val) = self.pop() {
            total += val;
        }
        total
    }

    fn calculate_product(&mut self) -> i32 {
        let mut product = 1;
        while let Some(val) = self.pop() {
            product *= val;
        }
        product
    }
}

fn main() {
    let mut vm = BytecodeVM::new();
    vm.push(2);
    vm.push(3);
    vm.push(4); 

    let sum_result = vm.calculate_sum();
    println!("The total sum of the numbers was: {}", sum_result);

    // Re-populate stack for product calculation demonstration
    vm.stack.clear();
    vm.push(2);
    vm.push(3);
    vm.push(4); 

    let product_result = vm.calculate_product();
    println!("The total product of the numbers was: {}", product_result);
}
